from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson.objectid import ObjectId
from bson.json_util import dumps, loads
import json
from datetime import datetime

app = Flask(__name__)

# MongoDB connection
MONGO_URI = "mongodb://localhost:27017/"
DB_NAME = "cms_db"

try:
    client = MongoClient(MONGO_URI)
    db = client[DB_NAME]
    users_collection = db.users
    documents_collection = db.documents
    # Ensure indexes for faster queries
    users_collection.create_index("username", unique=True)
    documents_collection.create_index([("title", "text"), ("content", "text"), ("tags", "text")])
    print(f"Connected to MongoDB: {MONGO_URI} - Database: {DB_NAME}")
except Exception as e:
    print(f"Error connecting to MongoDB: {e}")
    exit(1)

# Helper function to serialize MongoDB documents to JSON
def serialize_doc(doc):
    if doc:
        # dumps handles ObjectId and datetime objects
        return json.loads(dumps(doc))
    return None

# --- User Profile Endpoints ---

@app.route('/users', methods=['POST'])
def create_user():
    user_data = request.get_json()
    if not user_data or not user_data.get('username') or not user_data.get('email'):
        return jsonify({"error": "Missing username or email"}), 400

    try:
        # Check if username or email already exists
        if users_collection.find_one({"username": user_data['username']}):
            return jsonify({"error": "Username already exists"}), 409
        if users_collection.find_one({"email": user_data['email']}):
            return jsonify({"error": "Email already exists"}), 409

        user_data['created_at'] = datetime.utcnow()
        result = users_collection.insert_one(user_data)
        new_user = users_collection.find_one({"_id": result.inserted_id})
        return jsonify(serialize_doc(new_user)), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/users', methods=['GET'])
def get_all_users():
    try:
        users = list(users_collection.find())
        return jsonify(serialize_doc(users)), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    try:
        user = users_collection.find_one({"_id": ObjectId(user_id)})
        if user:
            return jsonify(serialize_doc(user)), 200
        return jsonify({"error": "User not found"}), 404
    except Exception as e:
        return jsonify({"error": str(e)}), 400 # 400 for invalid ObjectId

@app.route('/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    update_data = request.get_json()
    if not update_data:
        return jsonify({"error": "No update data provided"}), 400

    try:
        # Prevent changing username or email to an existing one
        if 'username' in update_data and users_collection.find_one({"username": update_data['username'], "_id": {"$ne": ObjectId(user_id)}}):
            return jsonify({"error": "Username already exists"}), 409
        if 'email' in update_data and users_collection.find_one({"email": update_data['email'], "_id": {"$ne": ObjectId(user_id)}}):
            return jsonify({"error": "Email already exists"}), 409

        update_data['updated_at'] = datetime.utcnow()
        result = users_collection.update_one(
            {"_id": ObjectId(user_id)},
            {"$set": update_data}
        )
        if result.matched_count == 0:
            return jsonify({"error": "User not found"}), 404
        updated_user = users_collection.find_one({"_id": ObjectId(user_id)})
        return jsonify(serialize_doc(updated_user)), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/users/<user_id>', methods=['DELETE'])
def delete_user(user_id):
    try:
        result = users_collection.delete_one({"_id": ObjectId(user_id)})
        if result.deleted_count == 0:
            return jsonify({"error": "User not found"}), 404
        
        # Optionally, delete documents authored by this user
        documents_collection.delete_many({"author_id": ObjectId(user_id)})
        
        return jsonify({"message": "User and their documents deleted successfully"}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 400

# --- Document Endpoints ---

@app.route('/documents', methods=['POST'])
def create_document():
    doc_data = request.get_json()
    if not doc_data or not doc_data.get('title') or not doc_data.get('content') or not doc_data.get('author_id'):
        return jsonify({"error": "Missing title, content, or author_id"}), 400

    try:
        # Validate author_id
        author = users_collection.find_one({"_id": ObjectId(doc_data['author_id'])})
        if not author:
            return jsonify({"error": "Author not found"}), 404

        doc_data['author_id'] = ObjectId(doc_data['author_id']) # Convert to ObjectId
        doc_data['created_at'] = datetime.utcnow()
        doc_data['updated_at'] = datetime.utcnow()
        doc_data['tags'] = doc_data.get('tags', []) # Ensure tags is a list

        result = documents_collection.insert_one(doc_data)
        new_document = documents_collection.find_one({"_id": result.inserted_id})
        return jsonify(serialize_doc(new_document)), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/documents', methods=['GET'])
def get_all_documents():
    query_params = request.args
    query = {}

    if 'author_id' in query_params:
        try:
            query['author_id'] = ObjectId(query_params['author_id'])
        except:
            return jsonify({"error": "Invalid author_id"}), 400
    
    if 'tag' in query_params:
        query['tags'] = query_params['tag']

    if 'title' in query_params:
        query['title'] = {"$regex": query_params['title'], "$options": "i"} # Case-insensitive search

    try:
        documents = list(documents_collection.find(query))
        return jsonify(serialize_doc(documents)), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    try:
        document = documents_collection.find_one({"_id": ObjectId(doc_id)})
        if document:
            return jsonify(serialize_doc(document)), 200
        return jsonify({"error": "Document not found"}), 404
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    update_data = request.get_json()
    if not update_data:
        return jsonify({"error": "No update data provided"}), 400

    try:
        # If author_id is updated, ensure it's a valid ObjectId and exists
        if 'author_id' in update_data:
            author = users_collection.find_one({"_id": ObjectId(update_data['author_id'])})
            if not author:
                return jsonify({"error": "New author not found"}), 404
            update_data['author_id'] = ObjectId(update_data['author_id'])

        update_data['updated_at'] = datetime.utcnow()
        result = documents_collection.update_one(
            {"_id": ObjectId(doc_id)},
            {"$set": update_data}
        )
        if result.matched_count == 0:
            return jsonify({"error": "Document not found"}), 404
        updated_document = documents_collection.find_one({"_id": ObjectId(doc_id)})
        return jsonify(serialize_doc(updated_document)), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/documents/<doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    try:
        result = documents_collection.delete_one({"_id": ObjectId(doc_id)})
        if result.deleted_count == 0:
            return jsonify({"error": "Document not found"}), 404
        return jsonify({"message": "Document deleted successfully"}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/documents/search', methods=['GET'])
def search_documents():
    search_term = request.args.get('q', '')
    if not search_term:
        return jsonify({"error": "Please provide a search query 'q'"}), 400

    try:
        # Using text index for searching across title, content, tags
        # Requires a text index on the documents collection:
        # db.documents.create_index([("title", "text"), ("content", "text"), ("tags", "text")])
        documents = list(documents_collection.find(
            {"$text": {"$search": search_term}},
            {"score": {"$meta": "textScore"}} # Include text score
        ).sort([("score", {"$meta": "textScore"})])) # Sort by relevance

        return jsonify(serialize_doc(documents)), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

# --- Aggregation Pipelines ---

@app.route('/analytics/documents_per_user', methods=['GET'])
def get_documents_per_user():
    try:
        pipeline = [
            {
                "$group": {
                    "_id": "$author_id",
                    "count": {"$sum": 1}
                }
            },
            {
                "$lookup": {
                    "from": "users",
                    "localField": "_id",
                    "foreignField": "_id",
                    "as": "author_info"
                }
            },
            {
                "$unwind": "$author_info"
            },
            {
                "$project": {
                    "_id": 0,
                    "author_id": "$_id",
                    "username": "$author_info.username",
                    "email": "$author_info.email",
                    "document_count": "$count"
                }
            },
            {
                "$sort": {"document_count": -1}
            }
        ]
        
        result = list(documents_collection.aggregate(pipeline))
        return jsonify(serialize_doc(result)), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/analytics/popular_tags', methods=['GET'])
def get_popular_tags():
    try:
        pipeline = [
            {"$unwind": "$tags"}, # Deconstruct the tags array to output one document for each tag
            {
                "$group": {
                    "_id": "$tags",
                    "count": {"$sum": 1}
                }
            },
            {
                "$project": {
                    "_id": 0,
                    "tag": "$_id",
                    "document_count": "$count"
                }
            },
            {
                "$sort": {"document_count": -1}
            },
            {"$limit": 10} # Get top 10 popular tags
        ]
        result = list(documents_collection.aggregate(pipeline))
        return jsonify(serialize_doc(result)), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

